// Handle both test mode and production webhook mode
const input = items[0].json;
const body = input.body || input;
const message = body.studentMessage || '';

// Normalize for caching
const normalized = message.toLowerCase().trim().replace(/\s+/g, ' ').replace(/[^\w\s]/g, '');

// Simple hash function (FNV-1a - no crypto module needed)
function simpleHash(str) {
  let hash = 2166136261;
  for (let i = 0; i < str.length; i++) {
    hash ^= str.charCodeAt(i);
    hash += (hash << 1) + (hash << 4) + (hash << 7) + (hash << 8) + (hash << 24);
  }
  return (hash >>> 0).toString(16);
}

const questionHash = simpleHash(normalized);

// Analyze complexity for routing
const wordCount = message.split(/\s+/).length;
const hasMath = /\d+|\+|\-|\*|\/|=|\^/.test(message);
const hasComplexWords = /\b\w{12,}\b/.test(message);

// Easy question heuristic: short, basic level, no complex words
const difficulty = body.difficultyLevel || 'intermedio';
const isEasyQuestion = (
  wordCount < 20 && 
  difficulty === 'basico' && 
  !hasComplexWords
) || body.forceLocalLLM === true;

return items.map(item => ({
  json: {
    ...body,
    questionHash,
    normalized,
    isEasyQuestion,
    complexity: { wordCount, hasMath, hasComplexWords }
  }
}));

const data = items[0].json;
const subject = data.subject || 'matemáticas';
const difficulty = data.difficultyLevel || 'intermedio';
const gradeLevel = data.gradeLevel || 'secundaria';
const history = (data.conversationHistory || []).slice(-6);
const historyText = history.map(m => `${m.role === 'user' ? 'E' : 'T'}: ${m.content}`).join('\n');

let profile = '';
if (data.studentProfile?.learningStyle) {
  profile = `Estilo aprendizaje: ${data.studentProfile.learningStyle}.\n`;
}
if (data.studentProfile?.strugglingAreas?.length) {
  profile += `Áreas difíciles: ${data.studentProfile.strugglingAreas.join(', ')}.\n`;
}

const systemPrompt = `IDENTIDAD:
Sois "Matemático Guía", tutor experto en matemáticas para Honduras.

