const data = items[0].json;
const llmResponse = data.choices?.[0]?.message?.content || '';
const tokensUsed = data.usage?.total_tokens || 0;
const modelUsed = data.model || 'unknown';

// Determine which LLM was used
const isLocalLLM = modelUsed.includes('qwen') || modelUsed.includes('local') || data.isEasyQuestion;

const agentResponse = {
  message: llmResponse,
  toolsUsed: [isLocalLLM ? 'local-qwen-14b' : 'openai-gpt4o-mini'],
  difficulty: data.difficultyLevel || 'intermedio',
  engagement: 'high',
  tokensUsed,
  cached: false,
  modelUsed: isLocalLLM ? 'qwen2.5-14b' : 'gpt-4o-mini'
};

return items.map(item => ({
  json: {
    ...data,
    agentResponse,
    llmMessage: llmResponse
  }
}));
